import jwt
from typing import Dict

def decode_and_verify_jwt(token: str, secret_key: str, algorithm: str = 'HS256') -> Dict:
    try:
        # Decode the JWT token without verifying the signature
        decoded = jwt.decode(token, options={"verify_signature": False})
        
        # Verify the JWT token with the provided secret key and algorithm
        verified = jwt.decode(token, secret_key, algorithms=[algorithm])
        
        return {
            "decoded_payload": decoded,
            "verified_payload": verified
        }
    except jwt.ExpiredSignatureError:
        return {"error": "Token has expired"}
    except jwt.InvalidTokenError as e:
        return {"error": str(e)}

